+/* =============================================================================
+   TOAST NOTIFICATION SYSTEM
+   Queued, stacked, auto-dismissing toast notifications with progress bar.
+   ============================================================================= */
+
+.toast-container {
+  position: fixed;
+  bottom: var(--space-4);
+  right: var(--space-4);
+  z-index: var(--z-toast, 9000);
+  display: flex;
+  flex-direction: column-reverse;
+  gap: var(--space-2);
+  pointer-events: none;
+  max-width: 420px;
+  width: 100%;
+}
+
+.toast-item {
+  pointer-events: auto;
+  position: relative;
+  overflow: hidden;
+  background: var(--color-background-elevated, #1a1a2e);
+  border: 1px solid var(--color-border-subtle, #333);
+  border-radius: var(--radius-lg, 8px);
+  box-shadow: var(--shadow-lg, 0 8px 24px rgba(0, 0, 0, 0.4));
+  color: var(--color-text, #e0e0e0);
+  font-size: var(--text-sm, 0.875rem);
+  animation: toast-slide-in var(--duration-normal, 250ms) var(--ease-out, ease-out) forwards;
+}
+
+.toast-item--exiting {
+  animation: toast-slide-out var(--duration-fast, 150ms) var(--ease-in, ease-in) forwards;
+}
+
+.toast-item__body {
+  display: flex;
+  align-items: flex-start;
+  gap: var(--space-3, 0.75rem);
+  padding: var(--space-3, 0.75rem) var(--space-4, 1rem);
+}
+
+.toast-item__icon {
+  flex-shrink: 0;
+  display: flex;
+  align-items: center;
+  font-size: var(--text-base, 1rem);
+  line-height: 1;
+  margin-top: 1px;
+}
+
+.toast-item__content {
+  flex: 1;
+  min-width: 0;
+}
+
+.toast-item__title {
+  font-weight: var(--font-semibold, 600);
+  margin-bottom: 2px;
+}
+
+.toast-item__message {
+  color: var(--color-text-muted, #999);
+  line-height: var(--leading-relaxed, 1.6);
+}
+
+.toast-item__close {
+  flex-shrink: 0;
+  background: none;
+  border: none;
+  color: var(--color-text-dim, #666);
+  cursor: pointer;
+  padding: var(--space-1, 0.25rem);
+  border-radius: var(--radius-sm, 4px);
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  min-width: 28px;
+  min-height: 28px;
+  transition: color var(--duration-fast, 150ms) var(--ease-out, ease-out);
+}
+
+.toast-item__close:hover {
+  color: var(--color-text, #e0e0e0);
+}
+
+.toast-item__actions {
+  display: flex;
+  gap: var(--space-2, 0.5rem);
+  padding: 0 var(--space-4, 1rem) var(--space-3, 0.75rem);
+  padding-left: calc(var(--space-4, 1rem) + var(--space-3, 0.75rem) + 1rem);
+}
+
+/* Progress bar for auto-dismiss */
+.toast-item__progress {
+  position: absolute;
+  bottom: 0;
+  left: 0;
+  height: 2px;
+  background: var(--color-primary, #00ffff);
+  transition: width 100ms linear;
+  border-radius: 0 0 0 var(--radius-lg, 8px);
+}
+
+/* Variant colors */
+.toast-item--info .toast-item__icon {
+  color: var(--color-primary, #00ffff);
+}
+
+.toast-item--info .toast-item__progress {
+  background: var(--color-primary, #00ffff);
+}
+
+.toast-item--success .toast-item__icon {
+  color: var(--color-success, #22c55e);
+}
+
+.toast-item--success .toast-item__progress {
+  background: var(--color-success, #22c55e);
+}
+
+.toast-item--warning .toast-item__icon {
+  color: var(--color-warning, #f59e0b);
+}
+
+.toast-item--warning .toast-item__progress {
+  background: var(--color-warning, #f59e0b);
+}
+
+.toast-item--warning {
+  border-color: rgba(245, 158, 11, 0.25);
+}
+
+.toast-item--error .toast-item__icon {
+  color: var(--color-error, #ef4444);
+}
+
+.toast-item--error .toast-item__progress {
+  background: var(--color-error, #ef4444);
+}
+
+.toast-item--error {
+  border-color: rgba(239, 68, 68, 0.25);
+}
+
+/* Animations */
+@keyframes toast-slide-in {
+  from {
+    opacity: 0;
+    transform: translateX(100%) scale(0.95);
+  }
+  to {
+    opacity: 1;
+    transform: translateX(0) scale(1);
+  }
+}
+
+@keyframes toast-slide-out {
+  from {
+    opacity: 1;
+    transform: translateX(0) scale(1);
+  }
+  to {
+    opacity: 0;
+    transform: translateX(100%) scale(0.95);
+  }
+}
+
+/* Reduced motion */
+@media (prefers-reduced-motion: reduce) {
+  .toast-item {
+    animation: none;
+    opacity: 1;
+  }
+
+  .toast-item--exiting {
+    animation: none;
+    opacity: 0;
+  }
+}
+
+/* Mobile: position above ControlDeck, full width */
+@media (max-width: 640px) {
+  .toast-container {
+    bottom: calc(var(--space-4) + env(safe-area-inset-bottom, 0px) + 64px);
+    left: var(--space-3);
+    right: var(--space-3);
+    max-width: none;
+  }
+}

